<template>
  <IosCard
    title="角色关系分析"
    icon="fa-solid fa-heart"
    icon-color="#e91e63"
    hide-header
    :collapsible="false"
  >
    <div class="ios-alert ios-alert-info" style="margin-bottom: 20px">
      <i class="fa-solid fa-info-circle"></i>
      <span>分析角色卡和世界书，提取角色关系图谱。</span>
    </div>

    <!-- 分析来源 -->
    <div style="margin-bottom: 20px">
      <label class="ios-label">分析来源</label>
      <div style="display: flex; gap: 8px; flex-wrap: wrap">
        <div class="source-chip" :class="{ active: includeChar }" @click="includeChar = !includeChar">
          <i v-if="includeChar" class="fa-solid fa-check"></i>
          <i class="fa-solid fa-id-card"></i>
          <span>角色卡</span>
        </div>

        <IosSelect
          v-model="selectedWorldbook"
          :options="worldbookOptions"
          placeholder="从世界书读取…"
          style="min-width: 180px; flex: 1"
        />
      </div>
    </div>

    <!-- 进度条 -->
    <div v-if="isProcessing && progress > 0" style="margin: 20px 0">
      <div class="ios-progress">
        <div class="ios-progress-bar" :style="{ width: progress + '%', background: '#e91e63' }"></div>
      </div>
      <p style="text-align: center; margin-top: 8px; color: #e91e63; font-size: 13px">
        分析中... {{ progress.toFixed(0) }}%
      </p>
    </div>

    <!-- 按钮 -->
    <div style="display: flex; gap: 12px; margin-bottom: 20px">
      <IosButton
        variant="primary"
        :disabled="isProcessing || (!includeChar && !selectedWorldbook)"
        :loading="isProcessing"
        icon="fa-solid fa-heart"
        style="background: #e91e63"
        @click="handleAnalyze"
      >
        {{ isProcessing ? '分析中...' : '分析关系' }}
      </IosButton>
      <IosButton icon="fa-solid fa-trash" @click="output = ''"> 清空 </IosButton>
    </div>

    <!-- 输出 -->
    <div v-if="output" style="margin-top: 24px">
      <div style="display: flex; align-items: center; gap: 8px; margin-bottom: 12px">
        <i class="fa-solid fa-project-diagram" style="color: #e91e63"></i>
        <span style="font-size: 15px; font-weight: 600; color: #fff">角色关系图谱</span>
      </div>

      <div class="output-content">
        {{ output }}
      </div>

      <div style="margin-top: 16px; display: flex; gap: 12px; flex-wrap: wrap">
        <IosButton icon="fa-solid fa-copy" @click="copyResult"> 复制 </IosButton>
        <div style="flex: 1; min-width: 180px; display: flex; gap: 8px">
          <IosSelect
            v-model="insertWorldbook"
            :options="worldbookOptions"
            placeholder="插入到世界书..."
            style="flex: 1"
          />
          <IosButton v-if="insertWorldbook" icon="fa-solid fa-download" @click="insertToWorldbook"> 插入 </IosButton>
        </div>
      </div>
    </div>
  </IosCard>
</template>

<script setup lang="ts">
import { storeToRefs } from 'pinia';
import { computed, ref, watch } from 'vue';
import { useSettingsStore } from '../../settings';
import { copyToClipboard } from '../../utils';
import { callAIWithTavernSupport } from '../../utils/api';
import { translateError } from '../../utils/error-handler';
import { IosButton, IosCard, IosSelect } from '../ios';

const settingsStore = useSettingsStore();
const { settings } = storeToRefs(settingsStore);

const props = defineProps<{ availableWorldbooks: string[] }>();
const emit = defineEmits<{ (e: 'dataChange', data: any): void }>();

const expanded = ref(true);
const output = ref('');
const includeChar = ref(true);
const selectedWorldbook = ref('');
const insertWorldbook = ref('');
const isProcessing = ref(false);
const progress = ref(0);

// 世界书选项
const worldbookOptions = computed(() => props.availableWorldbooks.map(wb => ({ value: wb, label: wb })));

watch(
  [output, includeChar, selectedWorldbook],
  () => {
    emit('dataChange', {
      output: output.value,
      includeChar: includeChar.value,
      selectedWorldbook: selectedWorldbook.value,
    });
  },
  { deep: true },
);

const handleAnalyze = async () => {
  if (!includeChar.value && !selectedWorldbook.value) {
    window.toastr.warning('请选择至少一个分析来源');
    return;
  }

  try {
    isProcessing.value = true;
    progress.value = 0;
    window.toastr.info('正在分析角色关系...');

    let content = '';
    const tav = (window as any).TavernHelper;

    if (includeChar.value && tav?.getCharData) {
      const char = tav.getCharData('current');
      if (char) {
        content += `【主角色卡】\n角色名：${char.name || '未知'}\n`;
        const desc = char.description || char.data?.description;
        if (desc) content += `描述：${desc}\n`;
        const personality = char.personality || char.data?.personality;
        if (personality) content += `性格：${personality}\n`;
        content += '\n';
      }
    }

    if (selectedWorldbook.value && tav?.getWorldbook) {
      const entries = await tav.getWorldbook(selectedWorldbook.value);
      if (entries?.length) {
        content += `【世界书条目】\n`;
        entries.forEach((e: any) => {
          if (e.content) content += `[${e.name || e.comment || '条目'}]\n${e.content}\n\n`;
        });
      }
    }

    if (!content.trim()) {
      window.toastr.warning('没有找到可分析的内容');
      isProcessing.value = false;
      return;
    }

    const systemPrompt = `你是一个角色关系分析专家。请分析提供的角色设定，提取所有角色及其关系。

输出格式要求：
1. 首先列出所有角色
2. 用图谱形式展示关系：[恋人] [家人] [朋友] [敌对] 等
3. 对重要关系给出简短说明
4. 保持简洁，不要使用 emoji`;

    const messages = [
      { role: 'system', content: systemPrompt },
      { role: 'user', content: `请分析以下内容中的角色关系：\n\n${content}` },
    ];

    output.value = await callAIWithTavernSupport(messages, settings.value, {
      onProgress: (p: number) => (progress.value = p),
    });

    window.toastr.success('关系分析完成！');
  } catch (error) {
    console.error('关系分析失败:', error);
    window.toastr.error(translateError(error, '分析'));
  } finally {
    isProcessing.value = false;
    progress.value = 0;
  }
};

const copyResult = () => {
  if (!output.value) return;
  copyToClipboard(output.value, '关系图谱已复制');
};

const insertToWorldbook = async () => {
  if (!output.value || !insertWorldbook.value) return;
  try {
    const tav = (window as any).TavernHelper;
    if (tav?.createWorldbookEntries) {
      await tav.createWorldbookEntries(insertWorldbook.value, [
        {
          name: '角色关系图谱',
          content: output.value,
          keys: ['关系', '人物'],
          comment: '由猫猫工具自动生成',
          enabled: true,
        },
      ]);
      window.toastr.success('已插入到世界书');
      insertWorldbook.value = '';
    }
  } catch (e) {
    console.error('插入失败:', e);
    window.toastr.error('插入失败');
  }
};

defineExpose({
  setExpanded: (val: boolean) => (expanded.value = val),
  loadData: (data: any) => {
    if (data) {
      output.value = data.output || '';
      includeChar.value = data.includeChar ?? true;
      selectedWorldbook.value = data.selectedWorldbook || '';
    }
  },
});
</script>

